      const within24h = sortedNewestFirst.filter(p => p.ts >= cutoff);
      const refPoint = within24h.length > 0 ? within24h[within24h.length - 1] : sortedNewestFirst[sortedNewestFirst.length - 1];
      let delta24Pct = null;
